-- {"operators": "WINDOW", "complexity": "medium", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "ORDER_LINE"}
SELECT OL_W_ID, OL_D_ID, OL_O_ID, OL_AMOUNT, LAG(OL_AMOUNT, 1, 0) OVER (PARTITION BY OL_W_ID, OL_D_ID ORDER BY OL_O_ID) AS prev_amount, LEAD(OL_AMOUNT, 1, 0) OVER (PARTITION BY OL_W_ID, OL_D_ID ORDER BY OL_O_ID) AS next_amount, OL_AMOUNT - LAG(OL_AMOUNT, 1, 0) OVER (PARTITION BY OL_W_ID, OL_D_ID ORDER BY OL_O_ID) AS amount_delta FROM ORDER_LINE;
